// Get the post data from Instagram API response
const response = $input.first().json;
const posts = response.data || [];

// Filter to last 7 days
const oneWeekAgo = new Date();
oneWeekAgo.setDate(oneWeekAgo.getDate() - 7);
const recentPosts = posts.filter(p => new Date(p.timestamp) > oneWeekAgo);

// Calculate engagement rate for each post
const withEngagement = recentPosts.map(p => ({
  ...p,
  // Use reach if available, fall back to like_count as denominator estimate
  engagement_rate: ((p.like_count + p.comments_count) / Math.max(p.reach || p.like_count || 1, 1) * 100).toFixed(2),
  total_interactions: (p.like_count || 0) + (p.comments_count || 0),
  // Truncate caption for display
  caption_short: (p.caption || '(no caption)').substring(0, 80) + ((p.caption || '').length > 80 ? '...' : '')
}));

// Sort by total interactions descending
const sorted = withEngagement.sort((a, b) => b.total_interactions - a.total_interactions);

// Return top 5
const top5 = sorted.slice(0, 5);

// Also compute weekly totals for summary
const weeklyTotals = {
  total_posts: recentPosts.length,
  total_likes: recentPosts.reduce((sum, p) => sum + (p.like_count || 0), 0),
  total_comments: recentPosts.reduce((sum, p) => sum + (p.comments_count || 0), 0),
  avg_engagement_rate: recentPosts.length > 0
    ? (recentPosts.reduce((sum, p) => sum + parseFloat(((p.like_count + p.comments_count) / Math.max(p.reach || p.like_count || 1, 1) * 100)), 0) / recentPosts.length).toFixed(2)
    : '0.00'
};

return top5.map(post => ({
  json: {
    ...post,
    weekly_totals: weeklyTotals
  }
}));

