// Collect all post items with their AI summaries
const items = $input.all();

if (items.length === 0) {
  return [{ json: { html_report: '<p>No posts found in the last 7 days.</p>', subject: 'Weekly Report - No Posts' } }];
}

const weeklyTotals = items[0].json.weekly_totals || {};
const reportDate = new Date().toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' });

// Build HTML email
const postsHtml = items.map((item, idx) => {
  const post = item.json;
  const aiSummary = post.message?.content || post.choices?.[0]?.message?.content || 'No summary available.';
  return `
    <div style="border-left: 3px solid #333; padding-left: 12px; margin-bottom: 24px;">
      <p style="margin:0; font-size:13px; color:#888;">#${idx + 1} &mdash; ${new Date(post.timestamp).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}</p>
      <p style="margin:6px 0; font-weight:bold;">${post.caption_short}</p>
      <p style="margin:4px 0; font-size:14px;">
        Likes: <strong>${post.like_count || 0}</strong> &nbsp;
        Comments: <strong>${post.comments_count || 0}</strong> &nbsp;
        Engagement: <strong>${post.engagement_rate}%</strong>
      </p>
      <p style="margin:8px 0; font-size:14px; color:#444;">${aiSummary}</p>
    </div>
  `;
}).join('');

const summaryHtml = `
  <div style="background:#f5f5f5; padding:16px; border-radius:6px; margin-bottom:24px;">
    <h3 style="margin:0 0 8px 0;">This Week</h3>
    <p style="margin:0;">Posts published: <strong>${weeklyTotals.total_posts || items.length}</strong></p>
    <p style="margin:4px 0;">Total likes: <strong>${weeklyTotals.total_likes || 0}</strong></p>
    <p style="margin:4px 0;">Total comments: <strong>${weeklyTotals.total_comments || 0}</strong></p>
    <p style="margin:4px 0;">Avg engagement rate: <strong>${weeklyTotals.avg_engagement_rate || '0.00'}%</strong></p>
  </div>
`;

const fullHtml = `
  <div style="font-family: -apple-system, BlinkMacSystemFont, sans-serif; max-width:600px; margin:0 auto; padding:24px;">
    <h2 style="margin:0 0 4px 0;">Weekly Instagram Report</h2>
    <p style="margin:0 0 24px 0; color:#888; font-size:14px;">${reportDate}</p>
    ${summaryHtml}
    <h3 style="margin:0 0 16px 0;">Top 5 Posts</h3>
    ${postsHtml}
    <p style="font-size:12px; color:#999; margin-top:32px;">Generated by Ceiba / n8n. Review, adjust content plan for next week.</p>
  </div>
`;

return [{ json: {
  html_report: fullHtml,
  subject: `Weekly Instagram Report - ${reportDate}`
} }];
